input.new_string:
const PROCESSING_FEE = 5;

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      let base = 0;
      let firstInsurance = 0;
      for (const item of step.items) {
        if (item.type === "sword") {
          base += 100;
          firstInsurance += 10;
        }
      }
      return { premium: base + firstInsurance + PROCESSING_FEE };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

