export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export type StepResult =
  | { premium: number }
  | { payout: number; remainingCap: number };

export interface ScenarioResult {
  results: StepResult[];
}

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const basePremiumFor = (item: Item): number => {
  if (item.type === "sword") return 100;
  return 0;
};

const quotePremium = (items: Item[]): number => {
  const base = items.reduce((sum, item) => sum + basePremiumFor(item), 0);
  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
  return base + firstInsurance + PROCESSING_FEE;
};

const runStep = (step: Step): StepResult => {
  if (step.op === "quote") {
    return { premium: quotePremium(step.items) };
  }
  return { payout: 0, remainingCap: 0 };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  return { results: scenario.steps.map(runStep) };
};

